exercises.solution_code:
#include <iostream>
#include <iomanip>
#include <cmath>

int main() {
    const double TAX_RATE = 0.08;
    const double HUNDRED  = 100.0;

    int n;
    double price;
    std::cin >> n >> price;

    double subtotal = static_cast<double>(n) * price;
    double rawTotal = subtotal * (1.0 + TAX_RATE);
    double total    = std::round(rawTotal * HUNDRED) / HUNDRED;

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Items: "      << n        << "\n";
    std::cout << "Unit price: " << price    << "\n";
    std::cout << "Subtotal: "   << subtotal << "\n";
    std::cout << "Total: "      << total    << "\n";

    return 0;
}
